def test_fires_and_writes_matches_table(
    session_dir: Path, shim_succeeds: tuple[Path, Path]
) -> None:
    shim_path, capture_path = shim_succeeds
    _write_input(session_dir, PYTHON_TRACEBACK)
    result = _run(session_dir, pythonpath=shim_path)
    assert result.returncode == 0, f"stderr: {result.stderr}"
    assert "signal fired" in result.stdout

    md_path = session_dir / "prior-fix-matches.md"
    assert md_path.exists()
    md = md_path.read_text(encoding="utf-8")
    assert "Prior-fix matches" in md
    assert "fix::indexerror@2026-05-01" in md
    # Top-3 cap — 4th entity should not appear.
    assert "fix::extra@2026-02-01" not in md

    handoff = _load_handoff(session_dir)
    assert handoff["status"] == "fired"
    assert handoff["matches_count"] == 3
    assert handoff["signature"].startswith("IndexError ")
    assert handoff["matches_md_path"] == str(md_path)

    captured = json.loads(capture_path.read_text(encoding="utf-8"))
    assert captured["tool"] == "search_nodes"
    assert captured["args"]["query"] == handoff["signature"]


